/* ─── Date clear row ─── */
.date-clear-row {
  display: flex;
  align-items: center;
  gap: 6px;
}

.date-clear-btn {
  background: transparent;
  border: 1px solid var\(--border\);
  border-radius: var\(--radius-sm\);
  color: var\(--text-muted\);
